Can be useful with:
https://github.com/plutext/docx4j/blob/master/src/main/java/org/docx4j/fonts/RunFontSelector.java

```python
def lang_to_script(lang_tag):
  lang = lang_tag.split("-")[0]

  # <a:font script="Jpan" typeface="ＭＳ 明朝"/>
  if lang == "ja":
    return "Japan"

  # <a:font script="Hang" typeface="맑은 고딕"/>
  if lang == "ko":
    return "Hang"

  if lang == "zh":
    # <a:font script="Hans" typeface="宋体"/>
    if lang_tag == "zh_CN" or lang_tag:
      # Mainland China and Singapore both use simplified characters
      return "Hans"
    else:
      # < a:font script="Hant" typeface="新細明體"/>
      # Chinese (Traditional Han)
      return "Hant"

  # <a:font script="Arab" typeface="Arial"/>
  if lang == "ar":
    return "Arab"

  # <a:font script="Hebr" typeface="Arial"/>
  if lang in ("he", "yi", "iw"):
    return "Hebr"

  # <a:font script="Thai" typeface="Cordia New"/>
  if lang == "th":
    return "Thai"

  # <a:font script="Ethi" typeface="Nyala"/>
  if lang in ("ti", "bwo", "eth", "kxh", "mdy"):
    return "Ethi"
		
  # <a:font script="Beng" typeface="Vrinda"/>
  if lang in ("bn", "as", "mni"):
    return "Beng";
		
  # <a:font script="Gujr" typeface="Shruti"/>
  if lang == "gu":
    return "Gujr"
		
  # <a:font script="Khmr" typeface="DaunPenh"/>
  if lang == "km":
    return "Khmr"
		
  # <a:font script="Knda" typeface="Tunga"/>
  if lang == "kn":
    return "Knda"
		
  # <a:font script="Guru" typeface="Raavi"/>
  if lang == "pa":
    return "Guru"
		
  # <a:font script="Cans" typeface="Euphemia"/>
  if lang == "iu":
    return "Cans"
		
  # <a:font script="Cher" typeface="Plantagenet Cherokee"/>
  if lang == "chr":
    return "Cher"
		
  # <a:font script="Yiii" typeface="Microsoft Yi Baiti"/> omitted
	# see http://en.wikipedia.org/wiki/Yi_script
		
  # <a:font script="Tibt" typeface="Microsoft Himalaya"/>
  if lang == "bo":
    return "Tibt"
		
  # <a:font script="Thaa" typeface="MV Boli"/>
  if lang == "dv":
    return "Thaa"
		
  # <a:font script="Deva" typeface="Mangal"/>
  if lang in ("hi", "ks", "kok", "mr", "ne", "sa", "sd"):
